import{_ as i,o as a,c as t,aA as n}from"./chunks/framework.Bd2PSwVy.js";const c=JSON.parse('{"title":"API Conventions","description":"","frontmatter":{},"headers":[],"relativePath":"resources/design.md","filePath":"resources/design.md","lastUpdated":null}'),e={name:"resources/design.md"};function o(l,s,p,h,d,r){return a(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="API-Conventions" tabindex="-1">API Conventions <a class="header-anchor" href="#API-Conventions" aria-label="Permalink to &quot;API Conventions {#API-Conventions}&quot;">​</a></h1><p>StyledTables.jl uses two conventions for specifying columns with <code>=&gt;</code> pairs, each reflecting a different kind of operation.</p><p><strong><code>cols_*</code> functions: column → value</strong></p><p>Column modifier functions take the column as subject. Target a column and assign a property to it:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cols_label!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(tbl, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:bmi</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;BMI (kg/m²)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>This mirrors the <code>old =&gt; new</code> convention of <code>DataFrames.rename!</code>: what&#39;s being modified comes first.</p><p><strong><code>tab_*</code> functions: annotation → columns</strong></p><p>Table-level annotation functions take the annotation as subject. Define an annotation and specify which columns it covers:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">tab_spanner!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(tbl, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Demographics&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:age</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:sex</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">tab_footnote!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(tbl, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;PPP adjusted&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:gdp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:gni</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])</span></span></code></pre></div><p>The annotation comes first because it is the entity being created; the columns define its scope (and apart from that, it is also a whole lot more readable!).</p><p>In short, <code>cols_*</code> functions put the column first; <code>tab_*</code> functions put the label or annotation first.</p>`,11)])])}const g=i(e,[["render",o]]);export{c as __pageData,g as default};
